class UserRepository {
  constructor() {
    this.user = null; 
  }

  // Update the setUser method to merge new data with existing user data
  setUser(userData) {
    if (this.user) {
      this.user = { ...this.user, ...userData };
    } else {
      this.user = userData;
    }
  }

  getUser() {
    return this.user;
  }

  clearUser() {
    this.user = null;
  }

  isLoggedIn() {
    return this.user !== null;
  }
}

const userRepository = new UserRepository();
export default userRepository;
